import { generatedQuestionSchema, geminiResponseSchema } from '../validations.js';

/**
 * Validates the structure of questions generated by Gemini.
 * @param {Object} response - The parsed JSON response from Gemini.
 * @returns {Object} - { isValid: boolean, data: Object, errors: Array }
 */
export function validateGeminiResponse(response) {
  try {
    const validatedData = geminiResponseSchema.parse(response);
    
    if (validatedData.skipped) {
      return { isValid: true, data: validatedData, errors: [] };
    }

    // Additional validation for each question
    const errors = [];
    validatedData.questions.forEach((q, idx) => {
      const correctOptionExists = q.options.some(opt => opt.id === q.correctOptionId);
      if (!correctOptionExists) {
        errors.push(`Question ${idx + 1}: correctOptionId "${q.correctOptionId}" not found in options`);
      }
    });

    if (errors.length > 0) {
      return { isValid: false, data: validatedData, errors };
    }

    return { isValid: true, data: validatedData, errors: [] };
  } catch (error) {
    return { 
      isValid: false, 
      data: null, 
      errors: error.errors?.map(e => `${e.path.join('.')}: ${e.message}`) || [error.message] 
    };
  }
}

/**
 * Validates a single question structure.
 * @param {Object} question - A single question object.
 * @returns {boolean}
 */
export function isValidQuestion(question) {
  try {
    generatedQuestionSchema.parse(question);
    return question.options.some(opt => opt.id === question.correctOptionId);
  } catch {
    return false;
  }
}
